// enterprise-ai-development-company

import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import EnterpriseAIDevelopmentCompanyPage from "@screens/ai-screens/enterprise-ai-development-company";

const EnterpriseAIDevelopmentCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Enterprise AI Development Company", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.hire3dDesignerImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const validFaq = data?.allFaqJson?.nodes[0]?.faqs;
  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <EnterpriseAIDevelopmentCompanyPage db={db} faq={validFaq} />
      </main>
    </Layout_v2>
  );
};

export default EnterpriseAIDevelopmentCompany;
export const queryData = graphql`
  query MyQuery {
    hire3dDesignerImg: file(
      relativePath: { eq: "enterprise-ai-development-company.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "enterprise-ai-development-company" } }) {
      nodes {
        metaTitle
        title
        slug
        description
      }
    }
    allFaqJson(filter: { slug: { eq: "enterprise-ai-development-company" } }) {
      nodes {
        slug
        faqs {
          question
          answer
          status
        }
      }
    }
  }
`;
