import React, { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/all";
gsap.registerPlugin(ScrollTrigger);

const datas = [
  {
    id: 0,
    title: "1. Understanding Business Needs",
    desc: "We start by understanding your business goals, problems, and data so we can plan the right AI solution for your needs.",
  },
  {
    id: 1,
    title: "2. Planning",
    desc: "Our team develops an intelligent AI strategy and selects the appropriate tools and models to create a solution that is appropriate for your business process.",
  },
  {
    id: 2,
    title: "3. Development and Testing",
    desc: "We build the AI system step by step and test it carefully to make sure it works smoothly, gives accurate results, and fits your business needs.",
  },
  {
    id: 3,
    title: "4. Deployment and Support",
    desc: "After testing, we launch the AI solution in your system and provide ongoing support to keep it running well and updated when needed.",
  },
];

const DevelopmentProcess = () => {
  const timeLinecontainerRef = useRef(null);

  useEffect(() => {
    const boxes = gsap.utils.toArray(".time-line-box");

    boxes.forEach((box) => {
      ScrollTrigger.create({
        trigger: box,
        start: "top center",
        end: "bottom center",
        onEnter: () => box.classList.add("active"),
        onLeaveBack: () => box.classList.remove("active"),
      });
    });
  }, []);

  return (
    <section className="service-hero-wrapper gap-xl col_flex_column">
      <div className="col_flex_column gap-md">
        <span className="gradient-badge">Development Process</span>
        <h2 className="about-h3 c-text-center md-c-text-start">
          Our Enterprise AI Development Process
        </h2>
      </div>
      {/*  */}
      <div className="timeline-container" ref={timeLinecontainerRef}>
        <div className="timeline-stick"></div>

        {datas.map((data, index) => (
          <div
            key={data.id}
            className={`time-line-box ${
              index % 2 !== 0 ? "left-box" : "right-box"
            }`}
          >
            <div className="dot"></div>
            <div className="timeline-content item-start">
              <p className="about-p-two fw-600">{data.title}</p>
              <p className="about-p-two">{data.desc}</p>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default DevelopmentProcess;
